INSERT INTO feature_flags (key, description, global_enabled, "default") VALUES ('data_health.reverification', 'Per-tenant gate for the daily freshness re-verification sweep (reverifyContacts) and the on-demand "Re-verify now" action. OFF by default (fail-closed): while off the sweep no-ops for the tenant. Additionally requires a configured verifier (Reacher / Twilio) — with no verifier the run is a no-op even when this is on.', false, false) ON CONFLICT (key) DO NOTHING;
